; Generated by linker
.import __MAIN_START__, __MAIN_SIZE__
.import __BSS_RUN__, __BSS_SIZE__

.include "macros.inc"
.include "basic.inc"

.zeropage

; A pointer to the start of the program
program_ptr: .res 2

; A pointer to the current program line
line_ptr: .res 2

; The value that line_ptr should take after we finish executing the current line.
; May be modified by control statements like GOTO, GOSUB, RETURN, NEXT, etc.
next_line_ptr: .res 2

; The start of the variable name table
variable_name_table_ptr: .res 2

; The start of the variable value table; maintained as the end of the variable name table
value_table_ptr: .res 2

; The start of free space
free_ptr: .res 2

; The address of "high memory" that will not be touched by the interpreter
himem_ptr: .res 2

; The number of variables in the program
variable_count: .res 1

; Pointer to the variable value set by a statement like LET, INPUT, and READ
variable_value_ptr: .res 2

; Read/write position in line
lp: .res 1

; The next value of lp (analogous to next_line_ptr)
next_lp: .res 1

; Whether the program is not running, running, stopped, or awaiting reset.
program_state: .res 1

.code

; We treat this as zero.
.assert PS_STOPPED = 0, error

; Initializes a new program.
; Inserts an empty zero-length line -1 into the program space.

initialize_program:
        mvax    #(__MAIN_START__ + __MAIN_SIZE__), himem_ptr
        mvax    #(__BSS_RUN__ + __BSS_SIZE__), program_ptr  ; Set program_ptr to start of program space
        stax    next_line_ptr               ; Also set next_line_ptr
        ldy     #0                          ; Populate END statement starting at offset 0
        jsr     build_end_statement
        jsr     advance_next_line_ptr       ; Advance next_line_ptr to the next line
        mvax    next_line_ptr, variable_name_table_ptr  ; New value is the start of variable name table
        clc                                 ; Add 1 to variable_name_table_ptr to get value_table_ptr
        adc     #1
        sta     value_table_ptr
        txa
        adc     #0
        sta     value_table_ptr+1
        lda     #0                          ; Load zero into A
        tay                                 ; Write index is also zero
        sta     (variable_name_table_ptr),y ; Initialize variable name table to 0
        sta     variable_count              ; Initialize number of variables to 0
        sta     program_state               ; Set program state to stopped
        
; Fall through to reset_program_state

; Clears the runtime state of the program.
; value_table_ptr = the address of the variable value table, the next byte following the variable name table
; variable_count = the number of variables in the variable name table

reset_program_state:
        mva     variable_count, D       ; Use D to track the variable index
@reset_variable:
        dec     D
        bmi     @reset_heap
        lda     D
        jsr     set_variable_value_ptr
        jsr     initialize_variable
        jmp     @reset_variable

@reset_heap:
        lda     variable_count
        jsr     set_variable_value_ptr  ; Set variable_value_ptr to just past the last variable
        mvaa    variable_value_ptr, free_ptr    ; Set into free_ptr (the start of free space)
        mva     #OP_STACK_SIZE, osp     ; Initialize stack positions
        mva     #PRIMARY_STACK_SIZE, psp
        mva     #0, resume_line_ptr+1   ; Initialize resume_line_ptr high byte to 0 to disable CONT

; Fall through

; Sets next_line_ptr to program_ptr.
; Returns next_line_ptr in AX.
; BC SAFE, DE SAFE

reset_next_line_ptr:
        ldax    program_ptr
reset_next_line_ptr_ax:
        stax    next_line_ptr
        mvy     #Line::data, next_lp
        rts

; Builds a line containing an END statement at next_line_ptr.
; This function makes assumptions about these offsets.
; TODO: 30 bytes, try to reduce by just copying from a template since all values are constants

.assert Line::next_line_offset = 0, error
.assert Line::number = 1, error
.assert Line::data = 3, error

build_end_statement:
        ldy     #0                          ; Start at offset 0 to next_line_ptr
        lda     #Line::data+2               ; Next line offset is data offset +1 for next statement offset +1 for END
        sta     (next_line_ptr),y           ; Save as next line offset
        iny
        lda     #$FF                        ; Line number = -1
        sta     (next_line_ptr),y           ; Save line number low byte
        iny
        sta     (next_line_ptr),y           ; Line number high byte
        iny
        lda     #Line::data+2               ; Next line offset is also next statement offset
        sta     (next_line_ptr),y           ; Line number high byte
        iny
        lda     #ST_END                     ; END
        sta     (next_line_ptr),y           ; Save as next line offset
        rts

; Searches for a line in the program.
; This function needs to be reasonably fast because it will be called every time the program executes GOTO, 
; GOSUB, RESTORE, or any other function that requires a line number.
; AX = the line number
; Carry clear if ok (the line was found), carry set if error (line not found).
; Sets next_line_ptr if the line was found.
; If not found, next_line_ptr is left set to where the line would have been, i.e., pointing
; to the next-higher line.

find_line:
        stax    DE
        jsr     reset_next_line_ptr     ; Set next_line_ptr to beginning of program
        jmp     @test_line              ; Skip over first advance_line_ptr call
@next_line:      
        jsr     advance_next_line_ptr   ; Advance to the next line
@test_line:
        ldy     #Line::number+1         ; Index of high byte of line number
        lda     (next_line_ptr),y        
        cmp     E       
        bcc     @next_line              ; Line number high byte is <target; go to next line
        bne     @done                   ; Return with carry set
        dey                             ; High byte is equal; decrement Y to get low byte of line number
        lda     (next_line_ptr),y       ; Check the low byte of line number
        cmp     D                       ; Same logic for low byte
        bcc     @next_line     
        bne     @done                   ; If not the line then return with carry bit set
        clc                             ; If it was the line then return with carry clear
@done:        
        rts     

; Advances next_line_ptr to the next line.
; next_line_ptr = current next line (updated)
; X SAFE, BC SAFE, DE SAFE

advance_next_line_ptr:
        ldy     #Line::next_line_offset
        lda     (next_line_ptr),y       ; Get next line offset into A
advance_next_line_ptr_a:
        clc
        adc     next_line_ptr           ; Add line length to low byte of next_line_ptr
        sta     next_line_ptr           ; Save back
        bcc     @skip                   ; Don't need to change the high byte
        inc     next_line_ptr+1         ; Increment the high byte
@skip:
        mvy     #Line::data, next_lp
        rts        

; Updates the program based on the information in line_buffer.
; If the line number in line_buffer is in the program, remove it.
; If line_buffer contains a new line, then insert it into the program.

insert_or_update_line:
        ldax    line_buffer+Line::number    ; Load line number into AX
        jsr     find_line               ; Go find it
        bcs     @insert                 ; Not found, just insert the new line

; next_line_ptr points to a line that we have to remove.

        ldy     #Line::next_line_offset
        lda     (next_line_ptr),y       ; Get next line offset into A
        pha                             ; Save the next line offset on the stack; it will be the compact length
        jsr     advance_next_line_ptr   ; Advance next_line_ptr to next line
        pla                             ; Get the length of the line back off the stack
        ldy     #next_line_ptr          ; Select next_line_ptr as the pointer to move
        jsr     compact_a

; Insert the new line, if there is one.
; There is a line if next_line_offset is greater than the offset of the data field.
; next_line_ptr points to where this new line should go.

@insert:
        lda     line_buffer+Line::next_line_offset  ; Load length of line which should be <= 255
        tax                             ; Save in X since we'll need it again
        cmp     #Line::data             ; Compare next line offset with the offset of the data field
        beq     @finish                 ; If they're the same, line is blank, nothing to insert
        ldphaa  next_line_ptr           ; Push next_line_ptr onto stack so we can get it back later
        txa                             ; Copy line length back into A as the amount to expand
        ldy     #next_line_ptr          ; Select next_line_ptr as the pointer to move
        jsr     expand_a                ; Create space for the new line
        plstaa  dst_ptr                 ; Restore the previous next_line_ptr into dst_ptr (even if expand failed)
        bcs     @done                   ; Don't copy if expand failed
        mvaa    #line_buffer, src_ptr   ; Set up copy into the space for the new line
        lda     line_buffer+Line::next_line_offset  ; Length of the new line
        jsr     copy_bytes_a            ; Copy the line into the program

@finish:
        clc
@done:
        rts

; Expands a section of memory by increasing one of the zero-page pointers, and all subsequent pointers up to (but
; not including) himem_ptr, by some amount.
; This creates a new area of uninitialized memory at the pointer's original address, increasing the memory available
; to the section *before* the pointer we moved.
; AX = the amount to add to the pointer (the expand_a entry point sets X to 0)
; Y = the zero-page address of the pointer to increase

expand_a:
        ldx     #0                      ; Initialize high byte to 0
expand:
        stax    BC                      ; Store length in BC
        jsr     check_himem             ; Check if expansion will push BASIC memory past himem_ptr
        bcs     @done                   ; If check_himem failed then we fail
        clc                             ; Clear carry to prepare for addition
        lda     0,y                     ; Load the low byte of the pointer to increase
        sta     src_ptr                 ; Store it as source for copy
        adc     B                       ; Increase low byte
        sta     dst_ptr                 ; It's also the destination pointer
        iny                             ; Do the same thing for the high byte
        lda     0,y
        sta     src_ptr+1
        adc     C
        sta     dst_ptr+1
        jsr     calculate_bytes_to_move ; Knowing src_ptr we can calculate number of bytes to move
        dey                             ; Move Y back to low by of source pointer
@next_ptr:
        clc
        lda     0,y                     ; Do the same thing only without setting src_ptr and dest_ptr
        adc     B
        sta     0,y
        iny
        lda     0,y
        adc     C
        sta     0,y
        iny
        cpy     #himem_ptr              ; Is Y now pointing at himem_ptr?
        bne     @next_ptr               ; Nope, keep going
        jsr     copy_bytes_higher_de    ; Copy data up to the higher address
        clc                             ; Success
@done:
        rts

; Compacts memory by decreasing one of the zero-page pointers, and all subsequent pointers up to (but not including)
; himem_ptr, by some amount.
; We don't check if the amount to subtract would cause the pointer to crash into next-lower pointer in memory;
; this is assumed to never happen.
; This decreases the amount of memory available in the section *before* the pointer we moved.
; AX = the amount to subtract from the pointer (the expand_a entry point sets X to 0)
; Y = the zero-page address of the pointer to increase

compact_a:
        ldx     #0
compact:
        stax    BC                      ; Follow a similar pattern to expand, only we're subtracting
        sec
        lda     0,y
        sta     src_ptr
        sbc     B
        sta     dst_ptr
        iny
        lda     0,y
        sta     src_ptr+1
        sbc     C
        sta     dst_ptr+1
        jsr     calculate_bytes_to_move ; Calculate the number of byte to move
        dey                             ; Move Y back to low by of source pointer
@next_ptr:
        sec
        lda     0,y                     ; Otherwise subtract BC from this pointer
        sbc     B
        sta     0,y
        iny
        lda     0,y
        sbc     C
        sta     0,y
        iny
        cpy     #himem_ptr              ; Have we reached himem_ptr?
        bne     @next_ptr               ; Nope, keep going
        jsr     copy_bytes_de
        clc
        rts

; Calculates the bytes to move for both compact and expand as (free_ptr - src_ptr).
; Returns the number of bytes in DE.
; X SAFE, Y SAFE, BC SAFE

calculate_bytes_to_move:
        sec                       
        lda     free_ptr
        sbc     src_ptr
        sta     D                       ; Store low byte of length in D
        lda     free_ptr+1      
        sbc     src_ptr+1      
        sta     E                       ; High byte of length in E
        rts

; Checks if adding an amount to free_ptr will cause it to exceed himem_ptr.
; Returns carry set if this would happen, otherwise carry clear.
; AX = the amount to add to free_ptr
; Y SAFE, BC SAFE

check_himem:
        clc                             ; Do 16-bit add of size in AX to free_ptr
        adc     free_ptr                ; Add low byte
        sta     D                       ; Park the low byte of result in D
        txa                             ; High byte of size into A
        adc     free_ptr+1              ; Add high byte of free_ptr
        bcs     @done                   ; If carry is set after high byte add then address has overflowed
        cmp     himem_ptr+1             ; Compare high byte
        bcc     @done                   ; argument high byte < himem_ptr high byte
        bne     @done                   ; argument high byte > himem_ptr high byte (carry is set)
        lda     D                       ; High bytes are equal; compare low bytes
        cmp     himem_ptr
        bcc     @done                   ; argument low byte < himem_ptr low byte
        bne     @done                   ; argument low byte > himem_ptr low byte (carry is set)
        clc                             ; Pointers are equal; clear carry since this is success
@done:
        rts

; Calculates the offset of a variable in the value table and sets variable_value_ptr to point to it. Since
; the resulting variable_value_ptr is within the 64K address space, on return the carry will be clear.
; A = the variable index (0-127)
; Y SAFE, BC SAFE

set_variable_value_ptr:
        jsr     mul_value_size_a        ; Multiply by VALUE_SIZE; since MSB was clear, this will clear carry
        adc     value_table_ptr         ; Add to the value table offset
        sta     variable_value_ptr      ; Store low byte
        txa                             
        adc     value_table_ptr+1
        sta     variable_value_ptr+1
        rts

; Multiplies the value in AX by VALUE_SIZE (6).
; Y SAFE, BC SAFE

.assert VALUE_SIZE = 6, error

mul_value_size_a:
        ldx     #0                      ; Only multiply A by initializing high byte to 0     
mul_value_size:
        stax    DE                      ; Save into DE
        asl     A
        rol     E                       ; Shift one left to multiply by 2
        clc
        adc     D                       ; Add original low byte value to A
        sta     D
        txa                             ; Original high byte into A
        adc     E                       ; Add shfited value, completing multiplication by 3
        sta     E
        lda     D                       ; Load low byte of value
        asl     A                       ; Shift left to multiply by 2, completing multiplication by 6
        rol     E
        ldx     E                       ; Load high byte into X for return
        rts

; Clears the value of the variable referenced by variable_value_ptr.

initialize_variable:
        ldy     #0
        tya                             ; Set following bytes to 0
@next:
        sta     (variable_value_ptr),y
        iny
        cpy     #VALUE_SIZE
        bne     @next
        rts
